diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..902ea567db1e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1632,8 +1632,47 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     }
   }

-  // X % C0 + (( X / C0 ) % C1) * C0 => X % (C0 * C1)
-  if (Value *V = SimplifyAddWithRemainder(I)) return replaceInstUsesWith(I, V);
+  // Fold ceiling division idiom:
+  // lshr(X, K) + zext((X & (2^K - 1)) != 0) -> lshr(X + (2^K - 1), K)
+  // This is the ceiling division pattern (X + D - 1) / D where D = 2^K
+  {
+    Value *X;
+    const APInt *ShAmt, *MaskC;
+    if (match(LHS, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
+        match(RHS, m_OneUse(m_ZExt(m_OneUse(m_SpecificICmp(
+                                                  ICmpInst::ICMP_NE,
+                                                  m_OneUse(m_And(m_Specific(X),
+                                                                 m_APInt(MaskC))),
+                                                  m_ZeroInt())))))) {
+      // Check that the mask is (2^K - 1) where K is the shift amount
+      APInt Divisor = APInt::getOneBitSet(ShAmt->getBitWidth(), ShAmt->getZExtValue());
+      if (*MaskC == Divisor - 1) {
+        // Create X + (2^K - 1)
+        Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(X->getType(), *MaskC),
+                                          "", /*HasNUW=*/true, /*HasNSW=*/true);
+        // Create lshr(NewAdd, K)
+        return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(X->getType(), *ShAmt));
+      }
+    }
+    // Also handle commuted form
+    if (match(RHS, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
+        match(LHS, m_OneUse(m_ZExt(m_OneUse(m_SpecificICmp(
+                                                  ICmpInst::ICMP_NE,
+                                                  m_OneUse(m_And(m_Specific(X),
+                                                                 m_APInt(MaskC))),
+                                                  m_ZeroInt())))))) {
+      // Check that the mask is (2^K - 1) where K is the shift amount
+      APInt Divisor = APInt::getOneBitSet(ShAmt->getBitWidth(), ShAmt->getZExtValue());
+      if (*MaskC == Divisor - 1) {
+        // Create X + (2^K - 1)
+        Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(X->getType(), *MaskC),
+                                          "", /*HasNUW=*/true, /*HasNSW=*/true);
+        // Create lshr(NewAdd, K)
+        return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(X->getType(), *ShAmt));
+      }
+    }
+  }
+

   const APInt *C1;
   // (A & 2^C1) + A => A & (2^C1 - 1) iff bit C1 in A is a sign bit

